from smolagents import CodeAgent, tool

@tool
def research_topic(query: str) -> str:
    # Simulate web search
    return f'Research results for {query}: Key fact 1, fact 2.'

@tool
def check_seo(content: str) -> str:
    return 'SEO score: 85/100 - Good keyword density'

agent = CodeAgent(
    model='meta-llama/Llama-3.2-1B-Instruct',
    tools=[research_topic, check_seo],
    instructions="""Generate blog posts matching professional B2B brand voice.
    Always fact-check. Include SEO keywords naturally."""
)

result = agent.run('Write 300-word blog on AI ethics for tech executives')
print(result)

from smolagents import CodeAgent, tool

@tool
def generate_outline(topic: str) -> str:
    return f'Outline for {topic}:\n1. Intro\n2. Key points\n3. Conclusion'

@tool
def polish_content(draft: str, feedback: str) -> str:
    return f'Polished: {draft} [Applied: {feedback}]'

agent = CodeAgent(
    model='meta-llama/Llama-3.2-1B-Instruct',
    tools=[generate_outline, polish_content],
    instructions='Create complete articles: outline first, then draft, then polish.'
)

content = agent.run('AI content generation best practices - 500 words, professional tone')
print(content)

from smolagents import CodeAgent, tool
import re

@tool
def validate_brand_voice(content: str, brand: str) -> dict:
    tone_scores = {'professional': 0.9, 'concise': 0.8}
    return {'valid': all(v > 0.7 for v in tone_scores.values()), 'scores': tone_scores}

agent = CodeAgent(
    model='meta-llama/Llama-3.2-1B-Instruct',
    tools=[validate_brand_voice],
