print(result)

from smolagents import CodeAgent, tool

@tool
def fact_check(statements: list) -> dict:
    # Mock fact API
    verified = {s: 'VERIFIED' if 'AI' in s else 'UNVERIFIED' for s in statements}
    return verified

agent = CodeAgent(
    model='meta-llama/Llama-3.2-1B-Instruct',
    tools=[fact_check],
    instructions='Verify all factual claims before publishing.'
)

article = agent.run('Write about recent AI regulations - include 3 key facts')
print(article)
